#!/usr/bin/env python3
"""
╔══════════════════════════════════════════════════════════════╗
║       Context Manager for Claude Code — Installer            ║
║                                                              ║
║  Installs slash commands + skill globally.                   ║
║  Works in every Claude Code project after install.           ║
║                                                              ║
║  Usage:     python3 install.py                               ║
║  Uninstall: python3 install.py --uninstall                   ║
╚══════════════════════════════════════════════════════════════╝
"""

import os, sys, base64, zipfile, io, shutil, datetime, platform

SKILL_BUNDLE_B64 = ""

SKILL_NAME  = "context-manager"
WIN         = platform.system() == "Windows"
HOME        = os.path.expanduser("~")
CLAUDE_DIR  = os.path.join(HOME, ".claude")
SKILLS_DIR  = os.path.join(CLAUDE_DIR, "skills")
INSTALL_DIR = os.path.join(SKILLS_DIR, SKILL_NAME)

def check_python():
    major, minor = sys.version_info[:2]
    if major < 3 or (major == 3 and minor < 8):
        print(f"  ✗  Python 3.8+ required. You have {major}.{minor}")
        sys.exit(1)
    print(f"  ✓  Python {major}.{minor}")

def check_claude():
    if not os.path.isdir(CLAUDE_DIR):
        print(f"\n  ⚠  ~/.claude not found.")
        print(f"     Install Claude Code first: npm install -g @anthropic-ai/claude-code")
        ans = input("\n  Create ~/.claude and install anyway? [y/N]: ").strip().lower()
        if ans != "y":
            print("  Cancelled.")
            sys.exit(0)
    else:
        print(f"  ✓  Claude config found at {CLAUDE_DIR}")

def backup(path):
    if os.path.isdir(path):
        ts  = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        bak = f"{path}.backup.{ts}"
        shutil.move(path, bak)
        print(f"  ↩  Backed up existing → {bak}")

def extract():
    os.makedirs(SKILLS_DIR, exist_ok=True)
    data = base64.b64decode(SKILL_BUNDLE_B64)
    buf  = io.BytesIO(data)
    skills_count   = 0
    commands_count = 0

    with zipfile.ZipFile(buf, "r") as zf:
        for info in zf.infolist():
            rel = info.filename  # e.g. .claude/commands/tokenstatus.md
            if not rel or rel.endswith("/"):
                continue

            # skills go under ~/.claude/skills/context-manager/
            skill_prefix = ".claude/skills/context-manager/"
            if rel.startswith(skill_prefix):
                sub  = rel[len(skill_prefix):]
                dest = os.path.join(INSTALL_DIR, sub.replace("/", os.sep))
                os.makedirs(os.path.dirname(dest), exist_ok=True)
                with zf.open(info) as src, open(dest, "wb") as dst:
                    dst.write(src.read())
                if dest.endswith(".py") and not WIN:
                    os.chmod(dest, 0o755)
                skills_count += 1

            # commands go under ~/.claude/commands/
            cmd_prefix = ".claude/commands/"
            if rel.startswith(cmd_prefix):
                sub  = rel[len(cmd_prefix):]
                dest = os.path.join(CLAUDE_DIR, "commands", sub.replace("/", os.sep))
                os.makedirs(os.path.dirname(dest), exist_ok=True)
                with zf.open(info) as src, open(dest, "wb") as dst:
                    dst.write(src.read())
                commands_count += 1

    return skills_count, commands_count

def install():
    print()
    print("╔══════════════════════════════════════════════════════════════╗")
    print("║       Context Manager for Claude Code                        ║")
    print("╚══════════════════════════════════════════════════════════════╝")
    print()
    print("─" * 62)
    print("  Checking requirements …")
    print("─" * 62)
    check_python()
    check_claude()

    print()
    print("─" * 62)
    print("  Installing …")
    print("─" * 62)
    backup(INSTALL_DIR)
    sc, cc = extract()
    print(f"  ✓  {sc} skill files  → {INSTALL_DIR}")
    print(f"  ✓  {cc} slash commands → {os.path.join(CLAUDE_DIR, 'commands')}")

    print()
    print("═" * 62)
    print("  ✅  Installation complete!")
    print("═" * 62)
    print()
    print("  Slash commands now available in Claude Code:")
    print()
    print("    /tokenstatus          show token usage & savings")
    print("    /ignore-init          set up .claudeignore defaults")
    print("    /ignore-add           add a pattern to ignore")
    print("    /ignore-list          show current ignore list")
    print("    /topiccontext-create  map a feature area to files")
    print("    /usetopiccontext      restrict Claude to one topic")
    print("    /filecontext          pin to one file only")
    print("    /projectcontext       show full project map")
    print("    /remember             save a fact to CLAUDE.md")
    print("    /scope                lock Claude to one task")
    print("    /clearcontext         reset all restrictions")
    print()
    print("  ⚠  Restart Claude Code desktop app to load the commands.")
    print()

def uninstall():
    print()
    removed = []
    if os.path.isdir(INSTALL_DIR):
        ans = input(f"  Remove skill at {INSTALL_DIR}? [y/N]: ").strip().lower()
        if ans == "y":
            shutil.rmtree(INSTALL_DIR)
            removed.append("skill")

    cmd_dir = os.path.join(CLAUDE_DIR, "commands")
    cmd_files = [
        "tokenstatus.md","ignore-init.md","ignore-add.md","ignore-remove.md",
        "ignore-list.md","filecontext.md","filecontext-clear.md",
        "topiccontext-create.md","topiccontext-list.md","topiccontext-show.md",
        "topiccontext-delete.md","usetopiccontext.md","projectcontext.md",
        "clearcontext.md","remember.md","scope.md"
    ]
    ans = input(f"  Remove {len(cmd_files)} slash commands from {cmd_dir}? [y/N]: ").strip().lower()
    if ans == "y":
        for f in cmd_files:
            p = os.path.join(cmd_dir, f)
            if os.path.exists(p):
                os.remove(p)
        removed.append("commands")

    if removed:
        print(f"  ✓  Removed: {', '.join(removed)}")
        print("  Project .claudeignore and .topiccontext/ files are untouched.")
    else:
        print("  Nothing removed.")

if __name__ == "__main__":
    if "--uninstall" in sys.argv or "-u" in sys.argv:
        uninstall()
    else:
        install()
